export interface RawOrderEvent {
  id: string;
  status: string;
  total_amount: number;
  customer_name?: string | null;
}

export interface NormalizedOrderEvent {
  id: string;
  status: "completed" | "refunded" | "failed" | "unknown";
  amount: number;
  customer_name: string;
}

export interface Logger {
  warn(message: string): void;
}

export function normalizeOrderEvent(
  raw: RawOrderEvent,
  logger: Logger
): NormalizedOrderEvent {
  const status = normalizeStatus(raw.status, raw.id, logger);
  const amount = normalizeAmount(raw.total_amount);
  const customer_name = raw.customer_name ?? "Anonymous";

  return {
    id: raw.id,
    status,
    amount,
    customer_name,
  };
}

function normalizeStatus(
  rawStatus: string,
  id: string,
  logger: Logger
): NormalizedOrderEvent["status"] {
  switch (rawStatus) {
    case "PAID":
      return "completed";
    case "REFUNDED":
      return "refunded";
    case "FAILED":
    case "DECLINED":
      return "failed";
    default:
      logger.warn(
        `normalizeOrderEvent: unknown status "${rawStatus}" for order id "${id}"`
      );
      return "unknown";
  }
}

function normalizeAmount(cents: number): number {
  return parseFloat((cents / 100).toFixed(2));
}

